extra.modelCss:
/* Navbar responsiva (mobile-first) */

:root {
  --accent: #60a5fa;
  --border: rgba(255, 255, 255, 0.10);
  --radius: 14px;
}

.navbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding: 12px 16px;
  border: 1px solid var(--border);
  border-radius: var(--radius);
}

.brand {
  font-weight: 700;
}

.nav-toggle {
  width: 44px;
  height: 44px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: transparent;
  cursor: pointer;
}

.nav-toggle:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 3px;
}

.nav-links {
  display: none;
  flex-direction: column;
  gap: 10px;
  padding: 12px 0 0;
}

.nav-link {
  display: inline-flex;
  align-items: center;
  padding: 10px 12px;
  border-radius: 12px;
  text-decoration: none;
}

.nav-link:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 3px;
}

.nav-link.active {
  color: var(--accent);
}

/* Quando abrir no mobile */
.navbar.open {
  flex-wrap: wrap;
}

.navbar.open .nav-links {
  display: flex;
  width: 100%;
}

/* Desktop */
@media (min-width: 768px) {
  .nav-toggle {
    display: none;
  }

  .nav-links {
    display: flex;
    flex-direction: row;
    padding: 0;
  }
}
